```cpp
#include <iostream>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>

int main() {
    int fd[2];
    pipe(fd);  // Crée un pipe

    pid_t pid = fork();  // Crée un nouveau processus

    if (pid == -1) {
        std::cerr << "Erreur de fork()" << std::endl;
        return 1;
    } else if (pid == 0) {  // Code du processus fils
        close(fd[1]);  // Ferme l'écriture du pipe
        dup2(fd[0], STDIN_FILENO);  // Redirige l'entrée standard vers le pipe
        close(fd[0]);  // Ferme le descripteur inutile
        execlp("some_command", "some_command", (char*)0);  // Exécute une commande
        std::cerr << "Erreur d'exécution de la commande" << std::endl;
        return 1;
    } else {  // Code du processus père
        close(fd[0]);  // Ferme la lecture du pipe
        dup2(fd[1], STDOUT_FILENO);  // Redirige la sortie standard vers le pipe
        close(fd[1]);  // Ferme le descripteur inutile

        std::string input = "Bonjour, processus fils !";
        write(STDOUT_FILENO, input.c_str(), input.size());

        wait(NULL);  // Attend que le processus fils termine
    }

    return 0;
}
```

Ce petit programme magique crée un nouveau processus et connecte son entrée et sa sortie à un pipe, permettant ainsi une communication bidirectionnelle entre les processus. Joyeux programmage ! 🎉
